window.__QUIZ_DATA__=[{"id":"objective>Geography>2007>1","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of SERA DISTRICT and use it to answer this question      The feature marked G on the map represents a","images":["data:image/png;base64,"],"options":{"A":"cuesta","B":"mountain","C":"slope","D":"saddle"},"answer":"D","explanation":"The feature marked G on the map represents a saddle, being a dip or low point between two area of higher ground.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>2","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of SERA DISTRICT and use it to answer this question    The feature marked Y - Z is known as","images":["data:image/png;base64,"],"options":{"A":"plateau","B":"hanging valley","C":"convex slope","D":"dip slope"},"answer":"C","explanation":"The feature marked Y - Z is known as convex slope showing by a convex-contour line.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>3","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of SERA DISTRICT and use it to answer this question    What is the approximate length of River Tui?","images":["data:image/png;base64,"],"options":{"A":"2.5km","B":"3.6km","C":"4.5km","D":"5.5km"},"answer":"C","explanation":"The approximate length of River Tui is 4.5km which is gotten by using a thread to measure the length from the map, placing it on a ruler for knowing the exact cm, the conversion based on the scale of the map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>4","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of SERA DISTRICT and use it to answer this question    The highest point on the map is a little above","images":["data:image/png;base64,"],"options":{"A":"250m","B":"300m","C":"400m","D":"500m"},"answer":"C","explanation":"The highest point on the map is a little above 400m.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>5","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of SERA DISTRICT and use it to answer this question    River Lep flows from","images":["data:image/png;base64,"],"options":{"A":"West to South East","B":"North West to South West","C":"South to West","D":"North East to South West"},"answer":"A","explanation":"River Lep flows from West to South East as seen on the map of SERA DISTRICT.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>6","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of SERA DISTRICT and use it to answer this question    SERA may be described as a","images":["data:image/png;base64,"],"options":{"A":"fishing town","B":"coastal town","C":"nodal town","D":"gap town"},"answer":"C","explanation":"SERA may be described as a nodal town because it area is organized around a node, or by the focal point which is defined by interactions or connections.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>7","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of SERA DISTRICT and use it to answer this question    Which of the following towns are not intervisible?","images":["data:image/png;base64,"],"options":{"A":"Labe and Mongo","B":"Sera and Fafu","C":"Sera and Pita","D":"Ta and Pita"},"answer":"C","explanation":"The towns which are not intervisible are Sera and Pita.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>8","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of SERA DISTRICT and use it to answer this question    What is the approximate bearing of Labe from Mongo?","images":["data:image/png;base64,"],"options":{"A":"20\u00b0","B":"40\u00b0","C":"190\u00b0","D":"270\u00b0"},"answer":"D","explanation":"The approximate bearing of Labe from Mongo is 270\u00b0.  The bearing of Mongo from Labe is 90\u00b0 or N90\u00b0E","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>9","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Study the map of SERA DISTRICT and use it to answer this question    The feature marked Q is a","images":["data:image/png;base64,"],"options":{"A":"conical hill","B":"cliff","C":"knoll","D":"spur"},"answer":"D","explanation":"The feature marked Q is a spur because contour lines on a map depict a spur with the u or v pointing away from high ground.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>10","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of SERA DISTRICT and use it to answer this question    The relief feature marked P is a","images":["data:image/png;base64,"],"options":{"A":"meander","B":"cliff","C":"confluence","D":"broad valley"},"answer":"A","explanation":"The relief feature marked P is a meander showing evidence of an erosion feature.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>11","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following does not prove that the earth is spherical in shape?","images":[],"options":{"A":"Tilting of the earth on its axis","B":"The curved horizon of the earth","C":"The eclipse of the moon","D":"Aerial photographs of the earth taken by astronauts"},"answer":"A","explanation":"Of the following, Tilting of the earth on its axis does not prove that the earth is spherical in shape.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>12","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"During the equinoxes","images":[],"options":{"A":"there are 6 hours of darkness and 18 hours of daylight in the Northern Hemisphere","B":"there is complete darkness for 24 hours at the North Pole","C":"there is continuous daylight for 24 hours at the South Pole","D":"days and nights are equal in length for all places throughout the world"},"answer":"D","explanation":"During the equinoxes, the tilt of Earth's axis is inclined neither away from nor towards the Sun, the center of the Sun being in the same plane as the Earth's equator. This means that the Sun is exactly above the equator, which results in equal length of day and night across the globe.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2007>13","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The movement of the earth round the sun is termed the earth's","images":[],"options":{"A":"evolution","B":"revolution","C":"rotation","D":"orbit"},"answer":"B","explanation":"The movement of the earth round the sun is termed the earth's revolution. This is the journey Earth makes around the Sun in one year (approximately 365.25 days). This movement, combined with the tilt of Earth's axis, is what gives us our seasons.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2007>14","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Seasonal changes in weather and climate are caused by","images":[],"options":{"A":"rotation of the earth on its axis","B":"direct overhead sun on the Tropic of Cancer","C":"direct overhead sun on the Tropic of Capricorn","D":"revolution of the earth round the sun"},"answer":"D","explanation":"Seasonal changes in weather and climate are caused by the revolution of the earth round the sun. As the Earth orbits the Sun, the tilt of Earth's axis causes the amount of sunlight reaching different parts of Earth to change. This causes the changing seasons.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>15","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the distance between Accra, Latitude 5\u00b030'N and London, Latitude 51\u00b030'N?","images":[],"options":{"A":"5,406 km","B":"5,306 km","C":"5,216 km","D":"5,106 km"},"answer":"D","explanation":"Latitude difference = (51\u00b030 - 5\u00b030), being on the same latitude.  \u21d2 46\u00b0  Distance=\u03b8360\u00d72\u03c0R  where R = radius of the earth \u2248 6,400km    46360\u00d72\u00d7\u03c0\u00d76400=5,106km","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>16","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The annual rainfall data of a particular station can best be represented with a","images":[],"options":{"A":"simple line graph","B":"simple bar graph","C":"compound line graph","D":"cumulative bar graph"},"answer":"A","explanation":"The annual rainfall of a particular station can be best represented with a simple line graph because it is an effective graphing tool for displaying the average of each months on a graph.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>17","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Density maps are most appropriate for showing","images":[],"options":{"A":"the distribution of people in a place","B":"movement of crude oil to refineries","C":"relief features of a place","D":"temperature variation of a country"},"answer":"A","explanation":"Density maps are most appropriate for showing the distribution of people in a place. A density map is a type of thematic map that uses color or pattern to represent the density of a particular attribute in a geographic area. In this case, the attribute is the population, and the geographic area can be any defined space such as a city, country, or continent.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>18","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The area of low pressure around the Equator is the","images":[],"options":{"A":"Doldrums","B":"Horse latitudes","C":"Sub-tropical low","D":"Sub-tropical high"},"answer":"A","explanation":"The area of low pressure around the Equator is the intertropical convergence zone (ITCZ). It can also be called doldrums because it is a region where surface winds are often weak.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2007>19","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Rocks of the core of the earth are rich in","images":[],"options":{"A":"iron and nickel","B":"silicon and magnesia","C":"iron and magnesia","D":"silica and nickel"},"answer":"A","explanation":"The core of the Earth is primarily composed of iron and nickel. The core is divided into two parts: the inner core, which is solid and composed mostly of iron and nickel, and the outer core, which is molten and composed of iron, nickel, and small amounts of other metals.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>20","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following is an intrusive igneous rock?","images":[],"options":{"A":"Shale","B":"Granite","C":"Sandstone","D":"Marble"},"answer":"B","explanation":"Granite is an example of an intrusive igneous rock. Intrusive igneous rocks form when magma cools and solidifies beneath the Earth's surface. Granite is composed mainly of quartz and feldspar with minor amounts of mica, amphiboles, and other minerals.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>21","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following is not a metamorphic rock?","images":[],"options":{"A":"Slate","B":"Marble","C":"Loess","D":"Gneiss"},"answer":"C","explanation":"Metamorphic rocks are formed from the transformation of existing rock types in a process called metamorphism, which means 'change in form'. The original rock (protolith) is subjected to heat and pressure, causing profound physical or chemical change. The protolith may be a sedimentary, igneous, or existing metamorphic rock. The options Slate, Marble, and Gneiss are all examples of metamorphic rocks. However, Loess is not a metamorphic rock. It is a sedimentary rock, formed from the accumulation of wind-blown silt.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>22","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Chemical weathering take place most effectively where it is","images":[],"options":{"A":"dry all the time","B":"cold and wet","C":"warm and dry","D":"hot and wet"},"answer":"B","explanation":"Chemically weathering take place most effectively where it is warm and dry.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>23","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The Figure 1 represents","images":["data:image/png;base64,"],"options":{"A":"an overthrust fold","B":"a simple fold","C":"an asymmetrical fold","D":"a symmetrical fold"},"answer":"A","explanation":"The Figure 1 represents an overthrust fold which result from horizontal forces that cause crustal shortening (in its horizontal dimension) and crustal thickening.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>24","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The line FF is called","images":["data:image/png;base64,"],"options":{"A":"an isoline","B":"a line of fracture","C":"a syncline","D":"an anticline"},"answer":"B","explanation":"The Line FF is called a line of fracture in the diagram.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>25","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following is a feature of river deposition?","images":[],"options":{"A":"Levee","B":"Scree","C":"Barchan","D":"Morraine"},"answer":"A","explanation":"Levees are broad, low-ridges formed along the bank of the river during floods. It is a feature of river deposition.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>26","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The swash of a wave is more powerful than the backwash because it","images":[],"options":{"A":"carries more sand","B":"has the force of the breaking wave behind it","C":"brings more water","D":"has a long length"},"answer":"B","explanation":"The swash of a wave is more powerful than the backwash because it has the force of the breaking wave behind it.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>27","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following favours the formation of rift valleys?  I. Tensional forces in the earth's crust   II. Compressional forces in the earth's crust  III. Lateral forces in the earth's crust  IV. The subsistence of the rift valley floor","images":[],"options":{"A":"I and III only","B":"I, II and IV only","C":"I and II only","D":"II and III only"},"answer":"C","explanation":"Tensional forces in the earth's crust and compressional forces in the earth's crust favours the formation of rift valleys.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>28","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"A fog is most likely to develop when a","images":[],"options":{"A":"cold dry wind blows over a cold current","B":"warm moist wind blows over a cold current","C":"cold dry wind blows over a warm current","D":"warm moist wind blows over a warm current"},"answer":"D","explanation":"A fog is most likely to develop when a warm moist wind blows over a warm current.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>29","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The instrument used for measuring atmospheric pressure is","images":[],"options":{"A":"wind vane","B":"anemometer","C":"barometer","D":"wet bulb thermometer"},"answer":"C","explanation":"A barometer is an instrument used to measure atmospheric pressure. It can measure the pressure exerted by the atmosphere by using water, air, or mercury. Pressure tendency can forecast short term changes in the weather. Many measurements of air pressure are used within surface weather analysis to help find surface troughs, high pressure systems and frontal boundaries.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2007>30","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Humidity is the amount of","images":[],"options":{"A":"cloud cover in the sky","B":"water vapour in the atmosphere","C":"moisture needed to cause condensation","D":"mist in the atmosphere"},"answer":"B","explanation":"Humidity is the amount of water vapour present in the atmosphere. It is the invisible gas form of water. Humidity indicates the likelihood for precipitation, dew, or fog to be present. The amount of water vapour needed to achieve saturation increases as the temperature increases. As the temperature of a parcel of air becomes lower it will eventually reach the point of saturation without adding or losing water mass.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2007>31","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Convectional rains are most common in","images":[],"options":{"A":"Equatorial regions and Tropical Monsoon climates","B":"Polar regions and Mediterranean climates","C":"Temperate regions","D":"Temperate and Mediterranean regions"},"answer":"A","explanation":"Convectional rains are most common in Equatorial regions and Tropical Monsoon climates. This is because these regions are characterized by high temperatures that cause rapid evaporation and hence, high humidity. The warm air rises, cools and condenses to form clouds which result in rainfall. This type of rainfall is very common in the afternoon and early evening in these regions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>32","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The instrument used for measuring relative humidity is called","images":[],"options":{"A":"hygrometer","B":"wind vane","C":"anemometer","D":"thermometer"},"answer":"A","explanation":"A hygrometer is an instrument used for measuring the amount of humidity and water vapor in the atmosphere, in soil, or in confined spaces. Humidity measurement instruments usually rely on measurements of some other quantity such as temperature, pressure, mass, a mechanical or electrical change in a substance as moisture is absorbed.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2007>33","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Equal degree of cloudiness is represented by","images":[],"options":{"A":"isoneph","B":"isobar","C":"chloropleth map","D":"pie chart"},"answer":"A","explanation":"Equal degree of cloudiness is represented isoneph. Isoneph is a line on a map connecting points that have the same average percentage of cloudiness.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>34","subject":"Geography","year":"2007","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following is not a problem of overpopulation?","images":[],"options":{"A":"Widespread unemployment","B":"Inadequate workforce","C":"A rapid increase in population","D":"A decline in standard of health"},"answer":"B","explanation":"Overpopulation is an undesirable condition where the number of existing human population exceeds the carrying capacity of Earth. Overpopulation is caused by number of factors such as reduced mortality rate, better medical facilities, depletion of precious resources. However, 'Inadequate workforce' is not a problem of overpopulation. In fact, overpopulation can lead to an excess of workforce.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>35","subject":"Geography","year":"2007","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The largest man-made lake in Africa is","images":[],"options":{"A":"Volta","B":"Tana","C":"Malawi","D":"Kainji"},"answer":"D","explanation":"The largest man-made lake in Africa is Karji Lake. It is a reservoir on the Niger River formed by the Kaiji Dam.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2007>36","subject":"Geography","year":"2007","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Africa's exploitation of solar energy will result in the following except","images":[],"options":{"A":"less amount of solar energy received by plants for photosynthesis","B":"savings in liquid fuel","C":"savings on electricity cost","D":"reduction in the use of fuel wood"},"answer":"A","explanation":"Africa's exploitation of solar energy will result in less amount of solar energy received by plants for photosynthesis.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>37","subject":"Geography","year":"2007","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Which of the following mountains is not in Africa?","images":[],"options":{"A":"Tibesti","B":"Atlas","C":"Andes","D":"Ruwenzori"},"answer":"C","explanation":"The Andes mountain range is not in Africa. It is the longest continental mountain range in the world, located in South America. The other mountains listed, Tibesti, Atlas, and Ruwenzori, are all located in Africa.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>38","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"All the following are associated with rainfall in Africa except","images":[],"options":{"A":"movement of the ITCZ","B":"convectional nature of hot tropical air","C":"movement of moist air masses over higher ground","D":"on-shore movement of cold air"},"answer":"D","explanation":"Rainfall in Africa is influenced by the movement of the Inter-Tropical Convergence Zone (ITCZ), the convectional nature of hot tropical air, and the movement of moist air masses over higher ground. However, the on-shore movement of cold air is not typically associated with rainfall in Africa. This is because cold air is denser and contains less moisture than warm air, making it less likely to rise and form rain clouds.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>39","subject":"Geography","year":"2007","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Which of the following is a landlocked country?","images":[],"options":{"A":"Ghana","B":"Tunisia","C":"Burundi","D":"South Africa"},"answer":"C","explanation":"Land locked country or state is a sovereign state entirely enclosed by land, or whose only coastlines i.e on closed seas. Burundi includes the currently 49 landlocked countries.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>40","subject":"Geography","year":"2007","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following countries is a major producer of copper?","images":[],"options":{"A":"Chad","B":"Zamibia","C":"Burundi","D":"Morocco"},"answer":"B","explanation":"The ten leading countries in world copper production are chile, Peru, China, the United States, Australia, the Democratic Republic of the Congo, Zambia, Mexico, Indonesia and Russia.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>41","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"The dominant climatic elements that control soil development are","images":[],"options":{"A":"temperature and pressure","B":"precipitation and wind","C":"temperature and precipitation","D":"precipitation and humidity"},"answer":"C","explanation":"The dominant climatic elements that control soil development are temperature and precipitation. Temperature affects the rate of chemical reactions involved in soil formation, and it also affects the rate of physical weathering. Precipitation provides the water that is necessary for the chemical reactions of weathering, and it also physically breaks down rocks and minerals.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>42","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"The feeding relationship above shows a","images":["data:image/png;base64,"],"options":{"A":"symbiotic relationship","B":"parasitic relationship","C":"food chain","D":"food web"},"answer":"C","explanation":"The feeding relationship above shows a food chain. Food chain shows a linear feeding relationship.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2007>43","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Which of the following is a primary producer?","images":[],"options":{"A":"Snake","B":"Lizard","C":"Grass","D":"Grasshopper"},"answer":"C","explanation":"In an ecosystem, a primary producer, also known as an autotroph, is an organism that produces its own food from inorganic substances, using light or chemical energy. Grass, being a plant, is a primary producer because it uses photosynthesis to convert sunlight, water, and carbon dioxide into glucose for energy and growth.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2007>44","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"The relationship between the elements of an ecosystem is best described as","images":[],"options":{"A":"parasitic","B":"symbiotic","C":"multidirectional","D":"interdependent"},"answer":"D","explanation":"The relationship between the elements of an ecosystem is best described as interdependent. In an ecosystem, all living organisms, including plants, animals, and microorganisms, as well as the non-living components, such as soil, water, and air, are interconnected and depend on each other for survival and maintenance of the ecosystem's health.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>45","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following is not a characteristic of warm currents?","images":[],"options":{"A":"They flow mostly along the east coast of continents","B":"They flow from the polar region to the equatorial region","C":"They have a high surface temperature","D":"They flow from the equatorial to the polar region"},"answer":"B","explanation":"Warm currents are a part of the oceanic circulation system and they originate in the tropics and flow towards the poles. They do not flow from the polar region to the equatorial region as stated in option 2. This is a characteristic of cold currents, not warm currents.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>46","subject":"Geography","year":"2007","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Which of the following African countries does not export petroleum?","images":[],"options":{"A":"Nigeria","B":"Libya","C":"Kenya","D":"Botswana"},"answer":"C","explanation":"Kenya is not a petroleum exporting country in Africa.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>47","subject":"Geography","year":"2007","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The Sahel savanna vegetation is predominantly found in","images":[],"options":{"A":"Cote d'Ivoire","B":"Mauritania","C":"Morocco","D":"Sierra Leone"},"answer":"B","explanation":"The Sahel savanna vegetation is predominantly found in Mauritania. The Sahel is a transitional eco-climate zone between the Sahara desert to the north and the more fertile region to the south, known as the Sudanian Savanna. Mauritania, a country in West Africa, falls within this Sahel zone.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>48","subject":"Geography","year":"2007","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following is not a problem of timber exploitation in Tropical Africa?","images":[],"options":{"A":"Inadequate transport facilities","B":"Trees not in pure stand","C":"Difficult terrain","D":"Heavy rainfall"},"answer":"D","explanation":"Heavy rainfall is not a problem of timber exploitation in Tropical Africa.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2007>49","subject":"Geography","year":"2007","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"The largest off-shore island in Africa is the","images":[],"options":{"A":"Island of Madagascar","B":"Canary Island","C":"St. Helena Island","D":"Cape Verde Island"},"answer":"A","explanation":"The largest off-shore island in Africa is the Island of Madagascar. It is the fourth largest island in the world and is located in the Indian Ocean off the southeastern coast of Africa. The other options, Canary Island, St. Helena Island, and Cape Verde Island, are smaller in comparison.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2007>50","subject":"Geography","year":"2007","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Which of the following is not a capital city of an ECOWAS State?","images":[],"options":{"A":"Nairobi","B":"Lome","C":"Dakar","D":"Bissau"},"answer":"A","explanation":"Nairobi is the capital city of Kenya which is not an ECOWAS STATE OR COUNTRY. Lome - Togo, Dakar - Senegal, Bissau - Guinea Bissau.","marks":"1","difficulty":"1"}];